/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;

    // 1. Precalculate Prefix Sums for Even Numbers
    // PrefE[i] stores the count of even numbers in nums[0...i]
    const PrefE = new Array(N).fill(0);
    for (let i = 0; i < N; i++) {
        let count = (nums[i] % 2 === 0) ? 1 : 0;
        if (i > 0) {
            PrefE[i] = PrefE[i - 1] + count;
        } else {
            PrefE[i] = count;
        }
    }

    /**
     * Finds the index of the last element <= X in nums[0...N-1].
     * Uses binary search (similar to upper_bound - 1).
     * Returns -1 if all elements are > X.
     */
    const find_j = (X) => {
        let low = 0;
        let high = N - 1;
        let result_index = -1;

        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (nums[mid] <= X) {
                result_index = mid;
                low = mid + 1; // Try to find a larger index
            } else {
                high = mid - 1;
            }
        }
        return result_index;
    };

    /**
     * Calculates C(X): the count of remaining positive even numbers <= X.
     * @param {number} X - The upper bound to check.
     * @param {number} l - Query left index.
     * @param {number} r - Query right index.
     * @returns {number} The count C(X).
     */
    const calculate_C = (X, l, r) => {
        // Total even numbers <= X is floor(X/2)
        const totalEvens = Math.floor(X / 2);

        // Find j: index of the last element in nums <= X
        const j = find_j(X);

        let countRemoved = 0;

        // The range of indices in nums we care about is [l, r] intersected with [0, j]
        let r_prime = Math.min(r, j);

        if (r_prime >= l) {
            // Count evens in nums[l...r_prime] using prefix sums
            let count_up_to_r_prime = PrefE[r_prime];
            let count_before_l = (l > 0) ? PrefE[l - 1] : 0;
            countRemoved = count_up_to_r_prime - count_before_l;
        }

        return totalEvens - countRemoved;
    };

    const results = [];

    for (const [l, r, k] of queries) {
        // Binary Search for the smallest X such that C(X) >= k.
        // Lower bound: 2 (smallest positive even number)
        // Upper bound: A safe upper limit. Max k is 10^9. Max removed is 10^5. 2*10^9 + 10^5 is enough.
        let low = 2;
        let high = 3000000000; // 3 * 10^9
        let X_ans = high + 1;

        while (low <= high) {
            // Using Math.floor for mid calculation
            let mid = Math.floor((low + high) / 2);

            const count = calculate_C(mid, l, r);

            if (count >= k) {
                // mid is a potential answer, try for a smaller one
                X_ans = mid;
                high = mid - 1;
            } else {
                // mid is too small
                low = mid + 1;
            }
        }

        // X_ans is the smallest integer such that C(X_ans) >= k.
        // We need the smallest EVEN number X_final such that C(X_final) >= k.

        let X_final;
        if (X_ans % 2 === 0) {
            X_final = X_ans;
        } else {
            // If X_ans is odd, then C(X_ans) = C(X_ans - 1).
            // Since X_ans - 1 is even, it is the smallest even number that satisfies the condition.
            X_final = X_ans - 1;
        }

        results.push(X_final);
    }

    return results;
}

